mapper.select:
select * from sys_cost_category
where del_flag='0'
and category_name like concat('%', #{categoryName}, '%')
and status = #{status}
and parent_id = #{parentId}
order by order_num asc, category_id asc

mapper.update:
update sys_cost_category
set parent_id=#{parentId}, category_name=#{categoryName}, category_level=#{categoryLevel}, order_num=#{orderNum}, status=#{status}, unit_price=#{unitPrice}, update_by=#{updateBy}, update_time=now()
where category_id=#{categoryId}
